def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        base_penalty = 0.0
        complex_decay = 1.0
        nested_score = 0.0
        iterative_sum = 0.0
        multi_factor = 1.0
        toggler = True
        power_accum = 0.0
        weighted_sum = 0.0
        divisor = capacity + 1
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for a in range(1, 10):
                base_penalty += (ratio ** (2 * a)) / (a ** 2 + 1)
            for b in range(1, 6):
                complex_decay *= (1 - 1 / (ratio * 0.5 + b + 1))
            score = (ratio ** 6) / 3 + base_penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 2.5
            priorities[i] = score * complex_decay
        elif 3 < ratio <= 4:
            for c in range(1, 10):
                sign = (-1) ** c
                nested_score += sign * (ratio ** c) / (c + 3)
            for d in range(1, 7):
                complex_decay *= (1 - 1 / (d + ratio + 5))
            nested_score = abs(nested_score) * complex_decay * 15
            priorities[i] = nested_score
        elif 2 < ratio <= 3:
            for e in range(1, 15):
                if e % 3 == 0:
                    iterative_sum += (ratio ** e) / (e * 4)
                else:
                    iterative_sum -= (ratio ** e) / (e * 3)
            multiplier = 30 if ratio < 2.5 else 20
            score = abs(iterative_sum) * multiplier
            if ratio > 2.8:
                extra = 0
                for f in range(1, 8):
                    extra += (ratio ** f) / (f + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            for g in range(1, 20):
                if toggler:
                    power_accum += (ratio ** g) / (g * 5)
                else:
                    power_accum -= (ratio ** g) / (g * 7)
                toggler = not toggler
            if ratio < 1.3:
                weight = 28
            elif ratio < 1.7:
                weight = 18
            else:
                weight = 12
            score = abs(power_accum) * weight
            if ratio > 1.85:
                nested_extra = 0
                for h in range(1, 10):
                    nested_extra += (ratio ** h) / (h + 4)
                score += nested_extra * 3
            priorities[i] = score
        elif 0 < ratio <= 1:
            for j in range(1, 20):
                if j % 5 == 0:
                    weighted_sum += (ratio ** j) / (j * 7)
                elif j % 2 == 0:
                    weighted_sum -= (ratio ** j) / (j * 6)
                else:
                    weighted_sum += (ratio ** j) / (j * 8)
            if ratio < 0.1:
                multi_factor = 40
            elif ratio < 0.3:
                multi_factor = 28
            elif ratio < 0.5:
                multi_factor = 18
            elif ratio < 0.7:
                multi_factor = 12
            else:
                multi_factor = 7
            score = abs(weighted_sum) * multi_factor
            if ratio > 0.9:
                penalty_sum = 0
                for k in range(1, 10):
                    penalty_sum += (ratio ** k) / (k + 2)
                score += penalty_sum * 3
            priorities[i] = score
        else:
            priorities[i] = 0 if item == 0 else np.inf
        if priorities[i] != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (capacity + z))
            priorities[i] *= factor
            adjustment = 0.0
            for w in range(1, int(capacity)+2):
                adjustment += np.sin(w * ratio) / (w + 1)
            if adjustment > 0:
                priorities[i] /= (1 + adjustment)
            else:
                priorities[i] *= (1 - adjustment / 2)
        elif capacity <= 0:
            priorities[i] = np.inf
    return priorities
